python3 -c "
import os
for fpath in ['expo/.env', '.env']:
    if os.path.exists(fpath):
        with open(fpath,'r') as f:
            for line in f:
                if line.startswith('SUPABASE_SERVICE_ROLE_KEY='):
                    key = line.split('=',1)[1].strip().strip('\"').strip(\"'\")
                    with open('/tmp/sb_service.txt','w') as out:
                        out.write(key)
                    print(f'FOUND in {fpath}, KEY_LEN: {len(key)}')
                    break
                if line.startswith('SUPABASE_URL='):
                    val = line.split('=',1)[1].strip().strip('\"').strip(\"'\")
                    with open('/tmp/sb_url.txt','w') as out:
                        out.write(val)
                    print(f'URL found in {fpath}: {val}')
